const emailDraft = $input.first().json.output;

const lines = emailDraft.split('\n');

const subjectLine = lines.find(line => line.startsWith('Subject:'));
const subject = subjectLine ? subjectLine.replace('Subject:', '').trim() : 'No Subject';

const subjectIndex = lines.findIndex(line => line.startsWith('Subject:'));
const emailBody = subjectIndex !== -1 
  ? lines.slice(subjectIndex + 1).join('\n').trim() 
  : emailDraft;

return [{
  json: {
    subject: subject,
    email_body: emailBody
  }
}];

