const geocodeResult = $input.first().json;

// Check if we got valid results
if (!geocodeResult.results || geocodeResult.results.length === 0) {
  throw new Error(`Could not geocode location: ${geocodeResult.status}`);
}

// Extract lat/lng from first result
const location = geocodeResult.results[0].geometry.location;

// Get all the data from Edit Fields node
const editFieldsData = $('Edit Fields').first().json;

// Pass through all previous data plus coordinates
return [{
  json: {
    Location: editFieldsData.Location,
    Business: editFieldsData.Business,
    NumOfBusinesses: editFieldsData.NumOfBusinesses,
    Radius: editFieldsData.Radius,
    latitude: location.lat,
    longitude: location.lng,
    formatted_address: geocodeResult.results[0].formatted_address
  }
}];

const response = $input.first().json;

return [{
  json: {
    results: response.results || [],
    next_page_token: response.next_page_token || null,
    status: response.status,
    page_number: 1
  }
}];

const previousData = $('Store Page Token').first().json;
const newPageData = $input.first().json;

// Merge results
const allResults = [
  ...(previousData.results || []),
  ...(newPageData.results || [])
];

return [{
  json: {
    results: allResults,
    next_page_token: newPageData.next_page_token || null,
    page_number: (previousData.page_number || 1) + 1,
    status: newPageData.status
  }
}];

const input = $input.first().json.output[0].content[0].text;

const cleaned = input.replace(/```json\n?|```\n?/g, '').trim();
const parsed = JSON.parse(cleaned);

// Extract all variation values into an array
const variations = Object.values(parsed);

// Return as array of items for looping
return variations.map(variation => ({
  json: { searchTerm: variation }
}));

const allData = $input.all();
const allResults = [];

allData.forEach(item => {
  if (item.json && Array.isArray(item.json.data)) {
    item.json.data.forEach(searchResponse => {
      if (searchResponse.results && Array.isArray(searchResponse.results)) {
        allResults.push(...searchResponse.results);
      }
    });
  }
});

// Remove duplicates based on place_id
const uniqueResults = allResults.filter((result, index, self) =>
  index === self.findIndex(r => r.place_id === result.place_id)
);

// Return as single item with all results
return [{
  json: {
    results: uniqueResults,
    total_count: uniqueResults.length
  }
}];

// Initialize score and debug object
let score = 0;
const debug = {
  breakdown: {},
  raw_values: {},
  errors: []
};

try {
  // ====================
  // GOOGLE REVIEWS (max 30 points)
  // ====================
  const placeDetails = $('Search Places for Details').item?.json?.result;
  const rating = placeDetails?.rating || null;
  const reviewCount = placeDetails?.user_ratings_total || null;

  debug.raw_values.rating = rating;
  debug.raw_values.reviewCount = reviewCount;

  let ratingPoints = 0;
  let reviewPoints = 0;

  if (rating !== null) {
    if (rating < 3.5) ratingPoints = 15;
    else if (rating < 4.0) ratingPoints = 10;
    else if (rating < 4.5) ratingPoints = 5;
    else ratingPoints = 0;
  } else {
    ratingPoints = 15; // No rating = high opportunity
  }

  if (reviewCount !== null) {
    if (reviewCount < 10) reviewPoints = 15;
    else if (reviewCount < 50) reviewPoints = 10;
    else if (reviewCount < 100) reviewPoints = 5;
    else reviewPoints = 0;
  } else {
    reviewPoints = 15; // No reviews = high opportunity
  }

  score += ratingPoints + reviewPoints;
  debug.breakdown.rating_score = ratingPoints;
  debug.breakdown.review_score = reviewPoints;

  // ====================
  // WEBSITE QUALITY (max 20 points)
  // ====================
  const emailData = $('Email Extractor').item?.json?.data;
  const website = emailData?.domain || null;
  const emails = emailData?.emails || [];

  debug.raw_values.website = website;
  debug.raw_values.email_count = emails.length;

  let websitePoints = 0;

  if (!website || website === '' || website === 'null') {
    websitePoints = 20; // No website = high opportunity
  } else if (emails.length === 0) {
    websitePoints = 15; // Website exists but no emails found
  } else {
    websitePoints = 0; // Website + emails = good digital presence
  }

  score += websitePoints;
  debug.breakdown.website_score = websitePoints;

  // ====================
  // SOCIAL MEDIA PRESENCE (max 30 points)
  // ====================
  let socialPoints = 0;

  // Instagram
  const instagramData = $('Instagram').item?.json;
  const instagramFollowers = instagramData?.followersCount || null;

  debug.raw_values.instagram_followers = instagramFollowers;

  let instagramPoints = 0;
  if (!instagramData || instagramFollowers === null) {
    instagramPoints = 10; // No Instagram = high opportunity
  } else if (instagramFollowers < 100) {
    instagramPoints = 10; // Very low followers
  } else if (instagramFollowers < 500) {
    instagramPoints = 5; // Low followers
  }

  // Facebook
  const facebookData = $('Facebook').item?.json;
  const facebookLikes = facebookData?.likes || null;

  debug.raw_values.facebook_likes = facebookLikes;

  let facebookPoints = 0;
  if (!facebookData || facebookLikes === null) {
    facebookPoints = 10; // No Facebook = high opportunity
  } else if (facebookLikes < 100) {
    facebookPoints = 10; // Very low likes
  } else if (facebookLikes < 500) {
    facebookPoints = 5; // Low likes
  }

  // LinkedIn
  const linkedinData = $('Linkedin').item?.json;
  const linkedinFollowers = linkedinData?.FollowersCount || null;

  debug.raw_values.linkedin_followers = linkedinFollowers;

  let linkedinPoints = 0;
  if (!linkedinData || linkedinFollowers === null) {
    linkedinPoints = 5; // No LinkedIn
  } else if (linkedinFollowers < 100) {
    linkedinPoints = 3;
  }

  // Twitter/X
  const twitterData = $('X(Twitter)').item?.json;
  const twitterFollowers = twitterData?.followers_count || null;

  debug.raw_values.twitter_followers = twitterFollowers;

  let twitterPoints = 0;
  if (!twitterData || twitterFollowers === null) {
    twitterPoints = 5; // No Twitter
  } else if (twitterFollowers < 100) {
    twitterPoints = 3;
  }

  socialPoints = instagramPoints + facebookPoints + linkedinPoints + twitterPoints;
  score += socialPoints;

  debug.breakdown.instagram_score = instagramPoints;
  debug.breakdown.facebook_score = facebookPoints;
  debug.breakdown.linkedin_score = linkedinPoints;
  debug.breakdown.twitter_score = twitterPoints;
  debug.breakdown.social_total = socialPoints;

  // ====================
  // BUSINESS STATUS (max 20 points)
  // ====================
  const businessStatus = placeDetails?.business_status || null;

  debug.raw_values.business_status = businessStatus;

  let statusPoints = 0;
  if (!businessStatus) {
    statusPoints = 0; // Unknown status
  } else if (businessStatus !== 'OPERATIONAL') {
    statusPoints = 20; // Closed/temporarily closed = might need help reopening
  }

  score += statusPoints;
  debug.breakdown.status_score = statusPoints;

  // ====================
  // FINAL CALCULATIONS
  // ====================
  debug.breakdown.total_score = score;
  debug.breakdown.max_possible = 100;

  const priorityTier = score >= 75 ? 'High Opportunity' : 
                       score >= 50 ? 'Medium Opportunity' : 
                       'Low Opportunity';

  return [{
    json: {
      opportunity_score: score,
      priority_tier: priorityTier,
      score_breakdown: debug.breakdown,
      raw_values: debug.raw_values,
      scoring_timestamp: new Date().toISOString()
    }
  }];

} catch (error) {
  // If anything fails, return error details for debugging
  return [{
    json: {
      opportunity_score: 0,
      priority_tier: 'Error',
      error_message: error.message,
      error_stack: error.stack,
      debug_info: debug
    }
  }];
}

// Get the audit output from the Analyzer Agent
const auditOutput = $input.first().json.output;

// Parse JSON (handle both string and object formats)
let auditData;
try {
  // If it's already an object, use it directly
  if (typeof auditOutput === 'object' && auditOutput !== null) {
    auditData = auditOutput;
  } else {
    // If it's a string, parse it
    let cleanedContent = auditOutput.trim();

    // Remove markdown code blocks if present
    if (cleanedContent.startsWith('```json')) {
      cleanedContent = cleanedContent.replace(/```json\n?/g, '').replace(/```\n?$/g, '');
    } else if (cleanedContent.startsWith('```')) {
      cleanedContent = cleanedContent.replace(/```\n?/g, '').replace(/```\n?$/g, '');
    }

    auditData = JSON.parse(cleanedContent);
  }
} catch (error) {
  throw new Error(`Failed to parse audit JSON: ${error.message}\nRaw output: ${JSON.stringify(auditOutput)}`);
}

// Extract and structure the data
return [{
  json: {
    // Core identifiers
    business_name: auditData.business_name || 'Unknown Business',

    // Audit summary
    executive_summary: auditData.executive_summary || '',
    overall_score: auditData.overall_score || 0,
    score_justification: auditData.score_justification || '',

    // Structured findings (keep as objects for downstream processing)
    top_gaps: auditData.top_gaps || [],
    quick_wins: auditData.quick_wins || [],
    conversion_opportunities: auditData.conversion_opportunities || [],

    // Additional insights
    competitive_position: auditData.competitive_position || '',
    positive_finding: auditData.positive_finding || null,

    // Formatted versions for Airtable (convert arrays to strings)
    top_gaps_text: auditData.top_gaps 
      ? auditData.top_gaps.map((g, i) => `${i+1}. ${g.gap} (${g.urgency} urgency) - Impact: ${g.impact}`).join('\n\n')
      : '',

    quick_wins_text: auditData.quick_wins
      ? auditData.quick_wins.map((w, i) => `${i+1}. ${w.action} (${w.effort} effort) - ${w.expected_impact}`).join('\n\n')
      : '',

    conversion_opportunities_text: auditData.conversion_opportunities
      ? auditData.conversion_opportunities.map((c, i) => `${i+1}. ${c}`).join('\n\n')
      : '',

    // For email generation - extract top 3 gaps
    gap_1: auditData.top_gaps && auditData.top_gaps[0] ? auditData.top_gaps[0].gap : null,
    gap_2: auditData.top_gaps && auditData.top_gaps[1] ? auditData.top_gaps[1].gap : null,
    gap_3: auditData.top_gaps && auditData.top_gaps[2] ? auditData.top_gaps[2].gap : null,

    // Metadata
    audit_generated_at: new Date().toISOString(),

    // Pass through original business data for next nodes
    original_business_type: $('Search Places for Details').item?.json?.result?.types || [],
    original_location: $('Edit Fields').item?.json?.Location || '',
    original_record_id: $('Search Places for Details').item?.json?.place_id || ''
  }
}];

let output = $input.first().json.output;

// Remove markdown code blocks if present
if (typeof output === 'string') {
  output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  output = JSON.parse(output);
}

return [{
  json: {
    subject: output.subject_line,
    email_body: output.email_body
  }
}];

const inputUrl = $input.first().json.result.website;

try {
  const match = inputUrl.match(/^(https?:\/\/)?([^\/\?#]+)/i);

  if (!match) {
    throw new Error('Invalid URL format');
  }

  const protocol = match[1] || 'https://';
  const hostname = match[2];
  const baseUrl = `${protocol}${hostname}`;

  return {
    json: {
      original_url: inputUrl,
      formatted_url: baseUrl
    }
  };

} catch (error) {
  return {
    json: {
      original_url: inputUrl,
      formatted_url: null,
      error: 'Invalid URL'
    }
  };
}
